mapper.select:
SELECT s.sId AS sid, s.sNo AS sno, s.sName AS sname, s.sSex AS ssex, s.sClassId AS sclassid, c.cId AS cid, c.cName AS cname, cr.crId AS crid, cr.crName AS crname, yt.yId AS yid, CONCAT(yt.yYear, '-', yt.yTerm) AS yall, t.tId AS tid, t.tName AS tname, sc.scId AS scid, sc.scScore AS scscore, sc.scStatus AS scstatus, sc.scCreateDate AS sccreatedate FROM teaching tc INNER JOIN studentinfo s ON tc.tcClassId = s.sClassId LEFT JOIN classinfo c ON s.sClassId = c.cId LEFT JOIN courseinfo cr ON tc.tcCourseId = cr.crId LEFT JOIN yearterm yt ON tc.tcTermId = yt.yId LEFT JOIN teacherinfo t ON tc.tcTeacherId = t.tId LEFT JOIN scoreinfo sc ON sc.scStudentId = s.sId AND sc.scTermId = tc.tcTermId AND sc.scClassId = tc.tcClassId AND sc.scCourseId = tc.tcCourseId WHERE tc.tcTeacherId = #{teacherId}
AND tc.tcTermId = #{dto.tctermid}
AND tc.tcCourseId = #{dto.tccourseid}
AND tc.tcClassId = #{dto.tcclassid}
AND ( s.sNo LIKE CONCAT('%', #{dto.qkey}, '%') OR s.sName LIKE CONCAT('%', #{dto.qkey}, '%') )
AND IFNULL(sc.scStatus, 0) = #{dto.scstatus}
ORDER BY CASE WHEN IFNULL(sc.scStatus, 0) = 1 THEN 0 ELSE 1 END ASC, sc.scCreateDate DESC, sc.scScore DESC, s.sId ASC

select s.sId as sid, s.sNo as sno, s.sName as sname, s.sSex as ssex, s.sClassId as sclassid, c.cName as cname, c.cMajorId as cmajorid, m.mName as mname, s.sTel as stel from teaching tc inner join studentinfo s on tc.tcClassId = s.sClassId left join classinfo c on s.sClassId = c.cId left join majorinfo m on c.cMajorId = m.mId where tc.tcTeacherId = #{teacherId}
and tc.tcTermId = #{dto.tctermid}
and tc.tcClassId = #{dto.tcclassid}
and tc.tcCourseId = #{dto.tccourseid}
and ( s.sNo like concat('%', #{dto.qkey}, '%') or s.sName like concat('%', #{dto.qkey}, '%') )
order by s.sId asc
